    "import shap\n",
    "import torch\n",
    "import numpy as np\n",
    "\n",
    "# Model setup\n",
    "model.eval()\n",
    "model_cpu = model.cpu()\n",
    "\n",
    "# Use FULL test set (IMPORTANT)\n",
    "X_sample = X_test\n",
    "X_sample_t = torch.tensor(X_sample, dtype=torch.float32)\n",
